import { calculateArea } from "../calculateArea";

describe("calculateArea", () => {
  it("debe calcular el area multiplicando ancho por alto", () => {
    expect(calculateArea(1.5, 2)).toBe(3);
  });

  it("debe retornar cero si una de las dimensiones es cero", () => {
    expect(calculateArea(0, 2)).toBe(0);
  });

  it("debe lanzar error si una dimension es negativa", () => {
    expect(() => calculateArea(-1, 2)).toThrow(
      "Las dimensiones no pueden ser negativas"
    );
  });
});
